const item = $input.item.json;
const available = item.available;
const datetimeStr = $('Seta Data e Hora').first().json.dataInicio;

return [{
  json: {
    datetime: '',
    available: false,
    error:'iCalUID não localizado' 
  }
}];

// Definir horário de início e fim
const startHour = 8; // 08:00
const endHour = 18;  // 18:00
// Definir horário do intervalo de almoço
const lunchStartHour = 12; // 12:00
const lunchEndHour = 14;   // 14:00
const timeSlots = [];
const iCalUID = $('Start').first().json.iCalUID;
const dateSlot = $('Start').first().json.dateSlots; // Recebendo a data do slot
// Obter a data e hora atuais
const now = new Date();
const currentDate = now.toISOString().split('T')[0]; // Formato YYYY-MM-DD
const currentHour = now.getHours();
const currentMinute = now.getMinutes();
// Verificar se a data do slot é a data atual
const isToday = dateSlot === currentDate;
// Gerar intervalos de 1 hora, excluindo o intervalo de almoço
for (let hour = startHour; hour < endHour; hour++) {
  // Pular os horários de almoço
  if (hour >= lunchStartHour && hour < lunchEndHour) {
    continue; // Pula este horário e vai para o próximo
  }

  // Se não for hoje, incluir todos os horários (exceto almoço)
  // Se for hoje, incluir apenas horários futuros (exceto almoço)
  if (!isToday || hour > currentHour || (hour === currentHour && currentMinute === 0)) {
    const startTime = `${hour.toString().padStart(2, '0')}:00`;
    const endTime = `${(hour + 1).toString().padStart(2, '0')}:00`;

    timeSlots.push({
      start: startTime,
      end: endTime,
      date: dateSlot,
      iCalUID: iCalUID
    });
  }
}
// Retornar os dados no formato esperado pelo n8n
return timeSlots.map(slot => ({ json: slot }));

